# Let's test by extracting just the is_fits function logic
# Simulating the fix

def is_fits(origin, filepath, fileobj, *args, **kwargs):
    if fileobj is not None:
        pos = fileobj.tell()
        sig = fileobj.read(30)
        fileobj.seek(pos)
        return sig == b'SIMPLE  =                    T / file does conform to FITS standard'
    elif filepath is not None:
        if filepath.lower().endswith(
            ('.fits', '.fits.gz', '.fit', '.fit.gz', '.fts', '.fts.gz')
        ):
            return True
    elif len(args) > 0 and isinstance(args[0], (list, tuple)):
        return True
    else:
        return False

# Test 1: The exact scenario from the bug report
try:
    result = is_fits('write', 'bububu.ecsv', None)
    print(f'Test 1 - non-FITS path, no args: {result}')
except IndexError as e:
    print(f'Test 1 FAILED - IndexError: {e}')

# Test 2: None path, no args
try:
    result = is_fits('write', None, None)
    print(f'Test 2 - None path, no args: {result}')
except IndexError as e:
    print(f'Test 2 FAILED - IndexError: {e}')

# Test 3: FITS path
try:
    result = is_fits('write', 'test.fits', None)
    print(f'Test 3 - FITS path: {result}')
except IndexError as e:
    print(f'Test 3 FAILED - IndexError: {e}')

# Test 4: None path, with HDUList-like arg
try:
    result = is_fits('write', None, None, [1, 2, 3])
    print(f'Test 4 - None path, list arg: {result}')
except IndexError as e:
    print(f'Test 4 FAILED - IndexError: {e}')

# Test 5: None path, with non-HDUList arg
try:
    result = is_fits('write', None, None, 'not_a_list')
    print(f'Test 5 - None path, non-list arg: {result}')
except IndexError as e:
    print(f'Test 5 FAILED - IndexError: {e}')

# Test 6: non-FITS path with list arg (should return None, same as original)
try:
    result = is_fits('write', 'bububu.ecsv', None, [1, 2, 3])
    print(f'Test 6 - non-FITS path with list arg: {result}')
except IndexError as e:
    print(f'Test 6 FAILED - IndexError: {e}')

print('All tests passed!')
""}

